def dedupe_tradelines(tradelines: List[ParsedTradeline]) -> List[ParsedTradeline]:
    seen: set[str] = set()
    out: List[ParsedTradeline] = []
    for tl in tradelines:
        key = f"{(tl.creditor or '').lower()}|{(tl.account_number or '').lower()}"
        if key in seen:
            continue
        seen.add(key)
        out.append(tl)
    return out

